                    x > 0.05 | is.na(x),
                    TRUE
                  )
                  d1 <- ifelse(
                    d1 == FALSE,
                    paste("FDR = ", round(x, digits = 4)),
                    ""
                  )
                  return(d1)
                }
              )
            ),
            size = ifelse(
              .data[["cluster_size"]] == 0,
              0,
              0.05
            )
          ),
          nudge_y = -0.125,
          color = "white",
          bg.color = "grey10",
          show.legend = FALSE
        ) +
        # Increased ratio color scale
        ggplot2::scale_fill_gradientn(
          "Log2FC",
          colors = c(
            "dodgerblue4",
            "azure",
            "firebrick3"
          )
        ) +
        ## Change scale
        ggnewscale::new_scale_color() +
        ggplot2::scale_size_area(
          max_size = 16
        ) +
        # text labels
        ggrepel::geom_text_repel(
          ggplot2::aes(
            x = .data[["x"]],
            y = .data[["y"]],
            label = .data[["label"]],
            alpha = ifelse(
              .data[["cluster_size"]] == 0,
              0.1,
              1
            ),
            size = ifelse(
              .data[["cluster_size"]] == 0,
              0.02,
              0.05
            )
          ),
          color = "black",
          bg.r = 0.01,
          bg.color = "white",
          nudge_x = 0,
          nudge_y = 0.09 * 1,
          show.legend = FALSE
        ) +
        # plot theme
        ms_theme1() + # nolint
        ms_theme_net() # nolint
    }
    if("sat_col" %in% names(net_edges) && "unsat_col" %in% names(net_edges)) { # nolint
      net_plot2 <- ggraph::ggraph(
        net_plot_lay
      ) +
        ggplot2::scale_fill_manual(
          "Pathway",
          values = col_univ() # nolint
        ) +
        # Boundary polygon for distinguishing different pathways
        ggplot2::geom_polygon(
          data = net_plot_lay2,
          ggplot2::aes(
            x = net_plot_lay2[["x"]],
            y = net_plot_lay2[["y"]],
            fill = net_plot_lay2[["synthesis_pathway"]]
          ),
          alpha = 0.5,
          color = "grey25",
          show.legend = FALSE
        ) +
        ## Color scale for edges
        ggplot2::scale_color_manual(
          "Log2FC",
          values = c("dodgerblue4", "white", "firebrick3")
        ) +
        ## Saturated lipid class links
        ggraph::geom_edge_link(
          ggplot2::aes(
            edge_alpha = ifelse(
              .data[["set_alpha_edge"]] == 0.25 | # nolint
                .data[["sat_col"]] == "white", # nolint
              0,
              .data[["set_alpha_edge"]]
            ),
            edge_color = .data[["sat_col"]],
            label = unlist(
              lapply(
                .data[[paste("FDR", cmp, "Sat", sep = "_")]],
                function(x) {
                  d1 <- ifelse(
                    !is.null(x), # nolint
                    x > 0.05 | is.na(x),
                    TRUE
                  )
                  d1 <- ifelse(
                    d1 == FALSE,
                    paste("FDR = ", round(x, digits = 4)),
                    ""
                  )
                  return(d1)
                }
              )
            )
          ),
          position = ggplot2::position_nudge(
            x = -0.03,
            y = 0.06
          ),
          edge_linetype = "twodash",
          edge_width = 1.25,
          end_cap = ggraph::circle(5, "mm"),
          lineend = "round",
          arrow = grid::arrow(
            length = ggplot2::unit(2, "mm"),
            type = "closed"
          ),
          angle_calc = "along",
          label_dodge = ggplot2::unit(1.4, "mm"),
          label_alpha = 0.8,
          show.legend = FALSE
        ) +
        ## Unsaturated lipid class links
        ggraph::geom_edge_link(
          ggplot2::aes(
            edge_alpha = ifelse(
              .data[["set_alpha_edge"]] == 0.25 | # nolint
                .data[["unsat_col"]] == "white", # nolint
              0,
              .data[["set_alpha_edge"]]
            ),
            edge_color = .data[["unsat_col"]],
            label = unlist(
              lapply(
                .data[[paste("FDR", cmp, "Unsat", sep = "_")]],
                function(x) {
                  d1 <- ifelse(
                    !is.null(x),
                    x > 0.05 | is.na(x),
                    TRUE
                  )
                  d1 <- ifelse(
                    d1 == FALSE,
                    paste("FDR = ", round(x, digits = 4)),
                    ""
                  )
                  return(d1)
                }
              )
            )
          ),
          position = ggplot2::position_nudge(
            x = 0.01,
            y = -0.04
          ),
          edge_linetype = "solid",
          edge_width = 1.25,
          end_cap = ggraph::circle(5, "mm"),
          lineend = "round",
          arrow = grid::arrow(
            length = ggplot2::unit(2, "mm"),
            type = "closed"
          ),
          angle_calc = "along",
          label_dodge = ggplot2::unit(-1.4, "mm"),
          label_alpha = 0.8,
          show.legend = FALSE
        ) +
        # general edge attributes
        ggraph::geom_edge_link(
          ggplot2::aes(
            label = ifelse(
              .data[["set_alpha_edge"]] == 0.25, # nolint
              "",
              .data[["enzyme_id"]]
            ),
            alpha = .data[["set_alpha_edge"]]
          ),
          edge_linetype = "solid",
          label_dodge = ggplot2::unit(1.2, "mm"),
          label_alpha = 0.6,
          angle_calc = "along",
          color = "grey50",
          show.legend = FALSE
        ) +
        # Background for node panels
        ggplot2::geom_rect(
          ggplot2::aes(
            xmin = ifelse(
              .data[["cluster_size"]] == 0,
              0,
              x - 0.175 # nolint
            ),
            ymin = ifelse(
              .data[["cluster_size"]] == 0,
              0,
              y - 0.175 # nolint
            ),
            ymax = ifelse(
              .data[["cluster_size"]] == 0,
              0,
              y + 0.175
            ),
            xmax = ifelse(
              .data[["cluster_size"]] == 0,
              0,
              x + 0.175
            )
          ),
          alpha = 0.7,
          fill = "grey",
          color = "grey25",
          show.legend = FALSE
        ) +
        # node points
        ggraph::geom_node_point(
          ggplot2::aes(
            alpha = ifelse(
              .data[["set_alpha"]] == 0, # nolint
              1,
              0
            )
          ),
          color = "grey75",
          show.legend = FALSE
        ) +
        ## Change scale
        ggnewscale::new_scale_color() +
        ggnewscale::new_scale_fill() +
        # Enrichment nodes
        ggraph::geom_node_point(
          ggplot2::aes(
            size = ifelse(
              is.na(.data[[paste(
                "Log2FC", cmp, sep = "_"
              )]]) |
                unlist(
                  lapply(
                    .data[[paste(
                      "Log2FC", cmp, sep = "_"
                    )]],
                    function(x) is.null(x)
                  )
                ),
              0,
              1
            ),
            fill = ifelse(
              is.na(.data[[paste(
                "Log2FC", cmp, sep = "_"
              )]]) |
                unlist(
                  lapply(
                    .data[[paste(
                      "Log2FC", cmp, sep = "_"
                    )]],
                    function(x) is.null(x)
                  )
                ),
              0.5,
              unlist(.data[[paste(
                "Log2FC", cmp, sep = "_"
              )]])
            ),
            color = ifelse(
              is.na(.data[[paste(
                "Log2FC", cmp, sep = "_"
              )]]) |
                unlist(
                  lapply(
                    .data[[paste(
                      "Log2FC", cmp, sep = "_"
                    )]],
                    function(x) is.null(x)
                  )
                ),
              "b",
              "a"
            )
          ),
          shape = 21,
          show.legend = FALSE
        ) +
        ggplot2::scale_color_manual(
          "Pathway",
          values = c("black", "white")
        ) +
        ## Change scale
        ggnewscale::new_scale_color() +
        # ChemRICH node labels
        shadowtext::geom_shadowtext(
          ggplot2::aes(
            x = x,
            y = y,
            label = ifelse(
              unlist(
                lapply(
                  .data[[paste("Log2FC", cmp, sep = "_")]],
                  function(x) is.null(x)
                )
              ),
              "",
              "Sat./Unsat."
            ),
            size = ifelse(
              .data[["cluster_size"]] == 0,
              0,
              0.05
            )
          ),
          nudge_y = -0.075,
          color = "white",
          bg.color = "grey25",
          show.legend = FALSE
        ) +
        # ChemRICH node FDR labels
        shadowtext::geom_shadowtext(
          ggplot2::aes(
            x = x,
            y = y,
            label = unlist(
              lapply(
                .data[[paste("FDR", cmp, sep = "_")]],
                function(x) {
                  d1 <- ifelse(
                    !is.null(x),
                    x > 0.05 | is.na(x),
                    TRUE
                  )
                  d1 <- ifelse(
                    d1 == FALSE,
                    paste("FDR = ", round(x, digits = 4)),
                    ""
                  )
                  return(d1)
                }
              )
            ),
            size = ifelse(
              .data[["cluster_size"]] == 0,
              0,
              0.05
            )
          ),
          nudge_y = -0.125,
          color = "white",
          bg.color = "grey10",
          show.legend = FALSE
        ) +
        # Increased ratio color scale
        ggplot2::scale_fill_gradientn(
          "Log2FC",
          colors = c(
            "dodgerblue4",
            "azure",
            "firebrick3"
          )
        ) +
        ## Change scale
        ggnewscale::new_scale_color() +
        ggplot2::scale_size_area(
          max_size = 16
        ) +
        # text labels
        ggrepel::geom_text_repel(
          ggplot2::aes(
            x = .data[["x"]],
            y = .data[["y"]],
            label = .data[["label"]],
            alpha = ifelse(
              .data[["cluster_size"]] == 0,
              0.1,
              1
            ),
            size = ifelse(
              .data[["cluster_size"]] == 0,
              0.02,
              0.05
            )
          ),
          color = "black",
          bg.r = 0.01,
          bg.color = "white",
          nudge_x = 0,
          nudge_y = 0.09 * 1,
          show.legend = FALSE
        ) +
        # plot theme
        ms_theme1() + # nolint
        ms_theme_net() # nolint
    }
  }
  return(net_plot2)
}

#' Scatter Plot
#'
#' Generates a scatter plot from a statistical results object for
#' a chosen comparison.
#'
#' @param df1 Input data frame.
#' @param type1 Scatter plot type (either "std" or "oxview").
#' If type is "oxview," a variable indicating either "Oxidized"
#' or "Unoxidized" lipids must be present in the input data frame.
#' @param xvar X-axis variable.
#' @param yvar Y-axis variable.
#' @param clvar Group variable.
#' @param oxvar (optional) If type is "oxview," the variable name
#' distinguishing oxidized from unoxidized lipids.
#' @param bns (optional) Bin number for scatter plot types using
#' stat_density_2d().
#' @return A scatter plot for the chosen treatment comparisons.
#' @examples
#'
#' # ms_plot_scatter(
#' #   df1 = dox,
#' #   type1 = "oxview",
#' #   xvar = "rt",
#' #   yvar = "mz",
#' #   clvar = "class"
#' # )
#'
#' @export
ms_plot_scatter <- function(
  df1,
  type1,
  xvar,
  yvar,
  clvar,
  oxvar = "ox",
  bns = 50
) {
  d <- df1
  if(type1 == "oxview") { # nolint
    ggplot2::ggplot(
      d,
      ggplot2::aes(
        x = .data[[xvar]], # nolint
        y = .data[[yvar]],
        color = .data[[clvar]],
        label = .data[[clvar]]
      )
    ) +
      ggplot2::scale_fill_manual(
        name = "Type",
        values = rep(
          col_univ()[[2]],
          length(unique(d[d[[oxvar]] == "Unoxidized", ][[clvar]]))
        )
      ) +
      ggplot2::stat_density_2d(
        data = d[d[[oxvar]] == "Unoxidized", ],
        ggplot2::aes(
          fill = d[d[[oxvar]] == "Unoxidized", ][[clvar]]
        ),
        geom = "polygon",
        alpha = 0.1,
        linewidth = 0.01,
        bins = bns,
        contour = TRUE,
        show.legend = FALSE
      ) +
      ggnewscale::new_scale_fill() +
      ggplot2::scale_fill_manual(
        name = "Type",
        values = rep(
          col_univ()[[1]],
          length(unique(d[d[[oxvar]] == "Oxidized", ][[clvar]]))
        )
      ) +
      ggplot2::stat_density_2d(
        data = d[d[[oxvar]] == "Oxidized", ],
        ggplot2::aes(
          fill = d[d[[oxvar]] == "Oxidized", ][[clvar]]
        ),
        geom = "polygon",
        alpha = 0.4,
        linewidth = 0.01,
        bins = bns,
        contour = TRUE,
        show.legend = FALSE
      ) +
      ggnewscale::new_scale_fill() +
      ggplot2::scale_color_manual(
        name = "Class",
        values = col_univ()
      ) +
      ggplot2::geom_point(
        shape = 16,
        size = 1,
        alpha = 0.6
      ) +
      ggrepel::geom_text_repel(
        data = setNames(
          aggregate(
            d[, c(yvar, xvar)],
            list(d[[clvar]]),
            FUN = median
          ),
          c(clvar, yvar, xvar
          )
        ),
        size = 3,
        bg.color = "grey0",
        color = "white",
        bg.r = 0.05
      ) +
      # Add Theme
      ms_theme1() + # nolint
      ggplot2::labs(
        y = "m/z",
        x = "RT (min.)",
        color = "Class"
      ) +
      ggplot2::theme(
        plot.margin = ggplot2::unit(
          c(
            0.1,
            0.1,
            0.1,
            0.1
          ),
          "cm"
        )
      )
  }
}
